#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn shaped_count() {
        assert_eq!(SHAPED_RECIPES.len(), 1285);
    }

    #[test]
    fn shapeless_count() {
        assert_eq!(SHAPELESS_RECIPES.len(), 272);
    }

    /// Spot-check: two planks vertically produce 4 sticks.
    #[test]
    fn stick_recipe() {
        let recipe = SHAPED_RECIPES
            .iter()
            .find(|r| r.result_id == 879 && r.result_count == 4 && r.width == 1 && r.height == 2)
            .expect("stick recipe not found");
        assert_eq!(recipe.ingredients, &[Some(43), Some(43)]);
    }

    /// Every shapeless recipe has its ingredients sorted ascending.
    #[test]
    fn shapeless_ingredients_sorted() {
        for recipe in SHAPELESS_RECIPES {
            assert!(
                recipe.ingredients.windows(2).all(|w| w[0] <= w[1]),
                "ingredients not sorted for result_id {}",
                recipe.result_id
            );
        }
    }
}
